import{_ as e,o as a,c as r,a2 as i}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Capy — Unique Patterns","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/capy/unique-patterns.md","filePath":"research/agents/capy/unique-patterns.md"}'),n={name:"research/agents/capy/unique-patterns.md"};function o(s,t,l,p,c,d){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="capy-—-unique-patterns" tabindex="-1">Capy — Unique Patterns <a class="header-anchor" href="#capy-—-unique-patterns" aria-label="Permalink to &quot;Capy — Unique Patterns&quot;">​</a></h1><blockquote><p>Planning/execution agent split, parallel-native design, task-based workflow, multiplayer collaboration, and a free-for-OSS commercial model.</p></blockquote><h2 id="_1-captain-build-split-hard-enforced-planning-vs-execution-separation" tabindex="-1">1. Captain/Build Split: Hard-Enforced Planning vs Execution Separation <a class="header-anchor" href="#_1-captain-build-split-hard-enforced-planning-vs-execution-separation" aria-label="Permalink to &quot;1. Captain/Build Split: Hard-Enforced Planning vs Execution Separation&quot;">​</a></h2><p>This is Capy&#39;s most architecturally distinctive pattern and the one most worth studying.</p><p><strong>The pattern</strong>: Two separate agents with non-overlapping capabilities. Captain can plan but cannot code. Build can code but cannot ask questions.</p><p><strong>Why it matters</strong>: Most coding agents use a single agent for both planning and execution, relying on prompt instructions like &quot;think step by step before coding.&quot; Capy enforces the separation at the platform level — Captain literally lacks the tools to write code, and Build literally lacks the ability to ask questions.</p><p><strong>The forcing function</strong>: Because Build cannot request clarification, Captain must produce thorough specs. Because Captain cannot write code, it doesn&#39;t skip ahead to implementation. This creates a natural quality gate that reduces wasted iterations.</p><p><strong>Trade-off</strong>: The rigidity can be a disadvantage for simple tasks where a single-agent loop would be faster. Creating a spec for a one-line bug fix adds overhead. The architecture optimizes for medium-to-large tasks where upfront planning pays off.</p><h2 id="_2-parallel-native-design" tabindex="-1">2. Parallel-Native Design <a class="header-anchor" href="#_2-parallel-native-design" aria-label="Permalink to &quot;2. Parallel-Native Design&quot;">​</a></h2><p><strong>The pattern</strong>: The entire platform is built around concurrent task execution, not sequential.</p><ul><li>Up to 25 concurrent jams on the Pro plan</li><li>Each task gets its own sandboxed Ubuntu VM</li><li>Git worktrees prevent merge conflicts between parallel branches</li><li>The dashboard shows all active tasks simultaneously</li></ul><p><strong>Why it matters</strong>: Most coding agents are inherently sequential — one task at a time, one context window. Capy&#39;s architecture treats parallelism as the default mode, not an add-on. This maps better to how engineering teams actually work (multiple tickets in a sprint, not one at a time).</p><p><strong>Comparison</strong>: Claude Code&#39;s sub-agents provide limited parallelism within a single task. Codex supports concurrent sessions. But Capy&#39;s VM-per-task model provides stronger isolation and true independence between parallel workstreams.</p><h2 id="_3-task-based-workflow-not-tab-based" tabindex="-1">3. Task-Based Workflow (Not Tab-Based) <a class="header-anchor" href="#_3-task-based-workflow-not-tab-based" aria-label="Permalink to &quot;3. Task-Based Workflow (Not Tab-Based)&quot;">​</a></h2><p><strong>The pattern</strong>: &quot;Think in tasks, not tabs.&quot; Each task is a first-class unit that bundles:</p><ul><li>The chat conversation (with Captain)</li><li>The git branch (via worktree)</li><li>The execution environment (VM)</li><li>The resulting pull request</li></ul><p><strong>Why it matters</strong>: Traditional IDEs organize around files and tabs. Even AI-enhanced IDEs (Cursor, Windsurf) maintain the tab-centric metaphor. Capy organizes around <strong>tasks</strong> — the unit of work, not the unit of code. This aligns the IDE with project management rather than file management.</p><h2 id="_4-multiplayer-collaboration" tabindex="-1">4. Multiplayer Collaboration <a class="header-anchor" href="#_4-multiplayer-collaboration" aria-label="Permalink to &quot;4. Multiplayer Collaboration&quot;">​</a></h2><p><strong>The pattern</strong>: Capy is collaborative by default:</p><ul><li>Tag teammates on tasks</li><li>Resume issues started by others</li><li>Shared visibility into all active tasks</li><li>3 seats included in the $20/month Pro plan</li></ul><p><strong>Why it matters</strong>: Most coding agents are single-player tools. Even cloud-based agents like Devin are primarily designed for individual use. Capy&#39;s multiplayer design reflects its positioning as a team platform, not a personal assistant.</p><h2 id="_5-git-worktree-isolation" tabindex="-1">5. Git Worktree Isolation <a class="header-anchor" href="#_5-git-worktree-isolation" aria-label="Permalink to &quot;5. Git Worktree Isolation&quot;">​</a></h2><p><strong>The pattern</strong>: Every task automatically uses a separate git worktree.</p><p><strong>Why it matters</strong>: This is the key enabler for parallel execution. Without worktree isolation, concurrent tasks modifying the same repository would create constant merge conflicts. By giving each task its own working directory (while sharing the underlying git object store), Capy enables true parallel development on a single repository.</p><p><strong>Technical note</strong>: Git worktrees are a native git feature (not Capy-specific), but Capy&#39;s automatic use of them as the default isolation mechanism is distinctive. Most other agents either don&#39;t address parallel execution or use branches without worktree isolation.</p><h2 id="_6-commercial-enterprise-focus-with-free-oss-tier" tabindex="-1">6. Commercial/Enterprise Focus with Free OSS Tier <a class="header-anchor" href="#_6-commercial-enterprise-focus-with-free-oss-tier" aria-label="Permalink to &quot;6. Commercial/Enterprise Focus with Free OSS Tier&quot;">​</a></h2><p><strong>The pattern</strong>: Capy is a commercial product with enterprise features:</p><ul><li>SOC 2 Type II certification (March 2026)</li><li>Custom Enterprise pricing</li><li>50,000+ engineer user base</li><li>Team-oriented pricing ($20/month for 3 seats)</li></ul><p>But also:</p><ul><li><strong>Free for open source projects</strong></li></ul><p><strong>Why it matters</strong>: The free-for-OSS policy differentiates Capy from other commercial agents (Devin, Factory/Droid) that don&#39;t offer OSS-specific pricing. It also serves as a growth lever — OSS developers try Capy for free, then bring it to their commercial work.</p><h2 id="_7-asynchronous-execution-model" tabindex="-1">7. Asynchronous Execution Model <a class="header-anchor" href="#_7-asynchronous-execution-model" aria-label="Permalink to &quot;7. Asynchronous Execution Model&quot;">​</a></h2><p><strong>The pattern</strong>: Once Build starts working, it runs fully asynchronously. The user can close the browser, work on other tasks, or go to lunch. Build will complete the task and open a PR.</p><p><strong>Why it matters</strong>: This is the natural outcome of the Captain/Build split — since Build can&#39;t ask questions, there&#39;s no reason for the user to watch. This contrasts with interactive agents (Claude Code, Aider) where the user is expected to monitor and approve each step.</p><p><strong>Trade-off</strong>: Less control during execution. If Build goes in the wrong direction, the user doesn&#39;t find out until the PR is ready. The mitigation is that Captain&#39;s spec should prevent this, but in practice some iteration is inevitable.</p><h2 id="summary-of-patterns" tabindex="-1">Summary of Patterns <a class="header-anchor" href="#summary-of-patterns" aria-label="Permalink to &quot;Summary of Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Key Insight</th></tr></thead><tbody><tr><td>Captain/Build split</td><td>Hard capability boundaries &gt; soft prompt instructions</td></tr><tr><td>Parallel-native</td><td>VM + worktree isolation enables true concurrency</td></tr><tr><td>Task-based workflow</td><td>Organize around work units, not files</td></tr><tr><td>Multiplayer</td><td>Team platform, not personal tool</td></tr><tr><td>Worktree isolation</td><td>Native git feature, elegantly applied</td></tr><tr><td>Commercial + free OSS</td><td>Growth lever and community goodwill</td></tr><tr><td>Async execution</td><td>Planning/execution split enables fire-and-forget</td></tr></tbody></table>',37)])])}const g=e(n,[["render",o]]);export{h as __pageData,g as default};
